import{c as a,Q as n,j as i,m as e}from"./chunks/framework.iD28w_5a.js";const k=JSON.parse('{"title":"032-gui-bitmap-icon-3 · 位图与图标","description":"","frontmatter":{"title":"032-gui-bitmap-icon-3 · 位图与图标"},"headers":[],"relativePath":"read-through/032-gui-bitmap-icon-3.md","filePath":"read-through/032-gui-bitmap-icon-3.md","lastUpdated":1779686691000}'),t={name:"read-through/032-gui-bitmap-icon-3.md"};function p(l,s,r,o,c,h){return n(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="_032-3-read-through-windowmanager-集成与测试" tabindex="-1">032-3 Read-through: WindowManager 集成与测试 <a class="header-anchor" href="#_032-3-read-through-windowmanager-集成与测试" aria-label="Permalink to &quot;032-3 Read-through: WindowManager 集成与测试&quot;">​</a></h1><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><p>本篇是 tag 032_gui_bitmap_icon 的第三篇也是最后一篇 read-through，聚焦于两个主题：WindowManager 如何集成桌面图标支持，以及覆盖整个 tag 功能的双轨测试体系。前两篇我们已经看了 Canvas 的 draw_bitmap 实现和编译期图标数据系统，这一篇把它们组装到一起——WindowManager 在 composite() 时渲染图标、在 handle_mouse() 时响应图标点击、测试系统验证像素渲染和命中测试的正确性。</p><p>关键设计决策一览：图标渲染在窗口之前（图标被窗口覆盖）、图标命中测试在窗口之前（但优先级低于窗口标题栏）、使用固定大小数组存储图标（最大 16 个）、pending action 机制解耦检测和执行。</p><h2 id="架构图" tabindex="-1">架构图 <a class="header-anchor" href="#架构图" aria-label="Permalink to &quot;架构图&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WindowManager</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├─ icons_[MAX_ICONS]     (DesktopIcon 数组)</span></span>
<span class="line"><span>   ├─ icon_count_           (已注册图标数)</span></span>
<span class="line"><span>   ├─ pending_icon_action_  (待处理动作)</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├─ add_desktop_icon(icon)    → 注册图标</span></span>
<span class="line"><span>   ├─ hit_test_icon(mx, my)     → 反向遍历，返回命中的图标</span></span>
<span class="line"><span>   ├─ consume_pending_icon_action() → 消费动作</span></span>
<span class="line"><span>   ├─ draw_desktop_icons(screen) → 渲染所有图标</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   └─ composite() 流程:</span></span>
<span class="line"><span>        clear(DESKTOP_COLOR)</span></span>
<span class="line"><span>        → draw_desktop_icons(screen)    ← 图标层</span></span>
<span class="line"><span>        → blit 每个窗口 (Z-order)      ← 窗口层</span></span>
<span class="line"><span>        → draw_cursor(screen)</span></span>
<span class="line"><span>        → flip()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><h2 id="代码精讲" tabindex="-1">代码精讲 <a class="header-anchor" href="#代码精讲" aria-label="Permalink to &quot;代码精讲&quot;">​</a></h2><h3 id="windowmanager-新增的图标相关成员" tabindex="-1">WindowManager 新增的图标相关成员 <a class="header-anchor" href="#windowmanager-新增的图标相关成员" aria-label="Permalink to &quot;WindowManager 新增的图标相关成员&quot;">​</a></h3><p>在 <code>kernel/gui/window_manager.hpp</code> 中，WindowManager 类新增了常量和成员来支持桌面图标。</p><p>常量定义：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> constexpr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint32_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MAX_ICONS        </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> constexpr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint32_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ICON_LABEL_COLOR </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00FFFFFF</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // White icon labels</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>MAX_ICONS = 16</code> 是一个经验值——一个桌面环境不太可能同时显示超过 16 个图标。这个限制用固定大小数组而不是动态容器来实现，因为我们不希望窗口管理器的图标管理依赖堆分配（虽然内核有堆，但减少运行时分配是好的实践）。</p><p>新增的成员变量：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DesktopIcon icons_[MAX_ICONS]    </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {};</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint32_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    icon_count_          </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">IconAction  pending_icon_action_ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IconAction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::None;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>icons_</code> 数组用值初始化（<code>= {}</code>），所有 DesktopIcon 的指针和数值都被初始化为零。<code>icon_count_</code> 追踪已注册的图标数量。<code>pending_icon_action_</code> 是一个&quot;一次性信箱&quot;——当用户点击图标时，handle_mouse 把动作写入这个字段；外部调用者（比如桌面事件循环）通过 consume_pending_icon_action() 读取并清空它。这种设计把&quot;检测到点击&quot;和&quot;执行动作&quot;解耦开来，让 handle_mouse 不需要知道动作的具体执行逻辑。</p><h3 id="add-desktop-icon-—-图标注册" tabindex="-1">add_desktop_icon — 图标注册 <a class="header-anchor" href="#add-desktop-icon-—-图标注册" aria-label="Permalink to &quot;add_desktop_icon — 图标注册&quot;">​</a></h3><p>方法逻辑很直接：如果图标数组未满，把传入的 DesktopIcon 复制到数组末尾，递增计数器，返回 true；如果满了返回 false。</p><p>这里有一个细节值得思考：为什么不做图标位置的去重或重叠检测？答案是&quot;不需要&quot;——DesktopIcon 是一个纯数据容器，WindowManager 只负责渲染和命中测试。如果开发者注册了两个完全重叠的图标，系统会忠实地在同一个位置画两个图标，并且后注册的那个在命中测试时优先（因为 hit_test_icon 反向遍历）。这种&quot;不做过多假设&quot;的设计给上层调用者最大的灵活性。</p><h3 id="hit-test-icon-—-命中测试" tabindex="-1">hit_test_icon — 命中测试 <a class="header-anchor" href="#hit-test-icon-—-命中测试" aria-label="Permalink to &quot;hit_test_icon — 命中测试&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DesktopIcon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> hit_test_icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int32_t</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> mx</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int32_t</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> my</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>方法从 icon_count_ - 1 开始向 0 反向遍历，对每个图标调用 contains(mx, my)。一旦找到包含该坐标的图标就立即返回指针。如果没有任何图标命中则返回 nullptr。</p><p>反向遍历的设计和窗口的 hit_test 逻辑一致——后注册的元素优先。这意味着如果两个图标重叠，用户点击重叠区域时会触发后注册的那个图标的动作。在实际使用中，图标不应该重叠（桌面环境的布局算法会确保这一点），但命中测试的行为是确定性的。</p><h3 id="consume-pending-icon-action-—-消费动作" tabindex="-1">consume_pending_icon_action — 消费动作 <a class="header-anchor" href="#consume-pending-icon-action-—-消费动作" aria-label="Permalink to &quot;consume_pending_icon_action — 消费动作&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IconAction</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> consume_pending_icon_action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    IconAction action </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pending_icon_action_;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pending_icon_action_ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IconAction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::None;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> action;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>一个简单的&quot;读取并清空&quot;操作。先保存当前值，重置为 None，返回保存的值。这个方法是一次性的——调用两次，第二次一定返回 None。</p><h3 id="draw-desktop-icons-—-渲染所有图标" tabindex="-1">draw_desktop_icons — 渲染所有图标 <a class="header-anchor" href="#draw-desktop-icons-—-渲染所有图标" aria-label="Permalink to &quot;draw_desktop_icons — 渲染所有图标&quot;">​</a></h3><p>这个方法在 composite() 中被调用，负责把所有注册的图标画到屏幕上。对每个图标，它做两件事：调用 <code>draw_bitmap()</code> 画图标图案，然后计算标签文字的居中位置并调用 <code>draw_text()</code> 画标签。</p><p>标签居中的计算逻辑：标签宽度等于字符数乘以字体字符宽度，标签起始 x 坐标等于图标中心 x 减去标签宽度的一半。图标中心 x 是 <code>icon.x + icon.width / 2</code>。这保证了无论标签多长（只要不超出屏幕），文字都显示在图标正下方居中位置。</p><h3 id="测试体系-—-内核端" tabindex="-1">测试体系 — 内核端 <a class="header-anchor" href="#测试体系-—-内核端" aria-label="Permalink to &quot;测试体系 — 内核端&quot;">​</a></h3><p>内核端测试在 <code>kernel/test/test_bitmap_icon.cpp</code> 中，约 516 行。测试入口函数 <code>run_bitmap_icon_tests()</code> 注册在 main_test.cpp 中，在内核启动后被调用。</p><p>测试的 setup 部分创建一个真实的 Framebuffer 对象并从 BootInfo 初始化（物理地址 0x7000）。每个测试创建自己的 Canvas 实例，执行操作后调用 flip()，然后通过 <code>g_fb.get_pixel()</code> 直接读取硬件帧缓冲区来验证像素值。</p><p>测试用例按功能分组：</p><p><strong>渲染测试组</strong>（test_bitmap_render_opaque, test_bitmap_render_at_origin, test_bitmap_render_larger）：验证 draw_bitmap 能正确地把像素写到指定位置。比如 test_bitmap_render_opaque 画一个 2x2 的四色位图，然后检查四个位置的像素值分别等于红、绿、蓝、白。</p><p><strong>透明测试组</strong>（test_bitmap_transparent_skip, test_bitmap_all_transparent）：先填充一个非零背景色，然后画一个部分透明的位图，验证透明位置的像素保留了背景色、不透明位置的像素被正确覆盖。</p><p><strong>裁剪测试组</strong>（test_bitmap_clip_right, test_bitmap_clip_bottom, test_bitmap_outside_canvas, test_bitmap_null_pixels）：验证位图在 Canvas 边缘和完全超出时的行为。test_bitmap_clip_right 把一个 4 像素宽的位图放在 Canvas 右边缘只剩 2 像素的位置，验证只有 2 个像素被写入。</p><p><strong>32x32 图标测试组</strong>（test_bitmap_render_test_icon, test_bitmap_render_test_icon2, test_bitmap_render_two_icons）：测试辅助函数 build_test_icon 和 build_test_icon2 生成的测试图标，验证透明角、边框、交叉线、显示区域等特征像素的颜色值。</p><p><strong>命中测试组</strong>（test_desktop_icon_contains_inside, test_desktop_icon_contains_outside, test_desktop_icon_contains_negative_position 等）：验证 DesktopIcon 的 contains 方法在各种边界条件下的行为，包括正负坐标、1x1 最小图标、IconAction 值不影响命中测试等。</p><h3 id="测试体系-—-宿主端" tabindex="-1">测试体系 — 宿主端 <a class="header-anchor" href="#测试体系-—-宿主端" aria-label="Permalink to &quot;测试体系 — 宿主端&quot;">​</a></h3><p>宿主端测试在 <code>test/unit/test_bitmap_icon.cpp</code> 中，约 545 行。它定义了一个 MockCanvas 类，用 <code>std::vector&lt;uint32_t&gt;</code> 模拟后端缓冲区。draw_bitmap 的实现和内核端完全一致（逐字面复制），因此可以独立验证渲染逻辑。</p><p>MockCanvas 和真实 Canvas 的区别在于：没有 Framebuffer 依赖、没有 pitch 的复杂性（pitch = width * 4）、通过 <code>back_pixel(x, y)</code> 方法读取后端缓冲区（真实 Canvas 需要通过 Framebuffer 的 get_pixel）。这使得宿主端测试的 setup 更简单、运行更快。</p><p>宿主端测试额外覆盖了一些内核端没有的边界用例：棋盘格模式（checkerboard，透明和不透明交替）、零宽零高位图（应该是 no-op）、1x1 位图在 Canvas 精确边界、多层叠加后透明像素保留底层内容等。</p><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><h3 id="决策-图标渲染层级——在窗口之前还是之后" tabindex="-1">决策：图标渲染层级——在窗口之前还是之后 <a class="header-anchor" href="#决策-图标渲染层级——在窗口之前还是之后" aria-label="Permalink to &quot;决策：图标渲染层级——在窗口之前还是之后&quot;">​</a></h3><p><strong>问题</strong>: 桌面图标应该渲染在窗口的上面还是下面？</p><p><strong>本项目的做法</strong>: 在窗口之前渲染（图标被窗口覆盖）。composite() 的顺序是：clear → draw_desktop_icons → blit windows → draw_cursor → flip。</p><p><strong>备选方案</strong>: 在窗口之后渲染（图标覆盖窗口），或者对每个窗口计算遮挡区域，只在窗口不遮挡的位置画图标。</p><p><strong>为什么不选备选方案</strong>: 图标覆盖窗口的视觉体验很奇怪——用户期望图标是桌面的一部分，窗口可以遮住桌面。精确遮挡计算虽然在视觉上最优，但实现复杂度高，需要逐像素判断遮挡关系。当前方案简单直观，符合桌面环境的常规层级模型。</p><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><ol><li><strong>双击检测</strong> — 区分单击和双击，单击选中图标，双击打开</li><li><strong>图标选中状态</strong> — 点击后图标高亮（反色或者添加蓝色边框）</li><li><strong>图标拖拽</strong> — 支持拖动桌面图标改变位置</li><li><strong>右键菜单</strong> — 右键点击图标弹出上下文菜单</li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>OSDev Wiki: <a href="https://wiki.osdev.org/VBE" target="_blank" rel="noreferrer">Drawing In a Linear Framebuffer</a> — 双缓冲渲染</li><li>SerenityOS: <a href="https://github.com/SerenityOS/serenity/blob/master/Userland/Libraries/LibGfx/Painter.cpp" target="_blank" rel="noreferrer">Painter.cpp</a> — <code>blit_filtered()</code> 中 alpha==0 跳过逻辑</li></ul>`,51)])])}const _=a(t,[["render",p]]);export{k as __pageData,_ as default};
